#include <stdio.h>

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n); 
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]); 
        }
        // Frequency counting using nested loops
        for (int i = 0; i < n; i++) {
            int count = 0;
            for (int j = 0; j < n; j++) {
                if (arr[i] == arr[j]) {
                    count++; // Count occurrences of arr[i]
                }
            }
            printf("%d ", count); 
        }
        printf("\n");
    }
    return 0;
}

