const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function freqCount(input) {
    const lines = input.trim().split('\n');
    let index = 0;
    let T = parseInt(lines[index++], 10);

    let results = [];

    while (T--) {
        const n = parseInt(lines[index++], 10); 
        const arr = lines[index++].split(' ').map(Number); 

        let frequency = [];

        // Frequency counting using nested loops
        for (let i = 0; i < n; i++) {
            let count = 0;
            for (let j = 0; j < n; j++) {
                if (arr[i] === arr[j]) {
                    count++; // Count occurrences of arr[i]
                }
            }
            frequency.push(count); // Store the frequency of the current element
        }
        results.push(frequency.join(' '));
    }
    console.log(results.join('\n'));
}

function main() {
    let input = '';

    rl.on('line', (line) => {
        input += line + '\n'; // Collect input lines
    });

    rl.on('close', () => {
        freqCount(input); // Process the collected input
    });
}

main();
